        if (*fmt == 37) {
            fmt = fmt + 1;
            if (*fmt == 37) { _putc_uart(37); }
            else if (ai == 0) { _fmt_one(*fmt, a0); ai++; }
            else { _putc_uart(37); _putc_uart(*fmt); }
        } else {
            _putc_uart(*fmt);
